const config = JSON.parse($input.item.json.shopify_config);
const storeUrl = config.store_url;
const accessToken = config.access_token;
const tenantId = $input.item.json.tenant_id;

// Calculate date range (last 24 hours)
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);

return {
  json: {
    tenant_id: tenantId,
    store_url: storeUrl,
    access_token: accessToken,
    created_at_min: yesterday.toISOString(),
    orders_url: `https://${storeUrl}/admin/api/2024-01/orders.json?created_at_min=${yesterday.toISOString()}&status=any&limit=250`,
    products_url: `https://${storeUrl}/admin/api/2024-01/products.json?limit=250`
  }
};

const orders = $input.item.json.orders || [];
const tenantId = $('Prepare API URLs').item.json.tenant_id;

return orders.map(order => {
  const landingSite = order.landing_site || '';
  const referringSite = order.referring_site || '';

  // Parse UTM params from landing site
  let source = '', medium = '', campaign = '';
  try {
    const url = new URL(landingSite, 'https://placeholder.com');
    source = url.searchParams.get('utm_source') || '';
    medium = url.searchParams.get('utm_medium') || '';
    campaign = url.searchParams.get('utm_campaign') || '';
  } catch(e) {}

  // Detect returning customer
  const isReturning = (order.customer?.orders_count || 0) > 1;

  // Extract line items
  const products = (order.line_items || []).map(li => ({
    sku: li.sku,
    name: li.title,
    quantity: li.quantity,
    price: parseFloat(li.price)
  }));

  return {
    json: {
      tenant_id: tenantId,
      external_id: `shopify_${order.id}`,
      order_date: order.created_at,
      revenue: parseFloat(order.total_price),
      currency: order.currency,
      customer_email: order.email,
      customer_id: order.customer?.id?.toString(),
      is_returning_customer: isReturning,
      source,
      medium,
      campaign,
      products: JSON.stringify(products),
      referring_site: referringSite
    }
  };
});
